#include "agi_api.h"
#include "module_integration.h"
#include <sstream>
#include <iomanip>

extern std::string generateResponse(const std::string& input);
extern void sv(const std::string& filename);
extern void ld(const std::string& filename);
extern "C" double get_current_valence();  // returns S.current_valence from main.cpp

AGI_API::AGI_API(int port) : server_(std::make_unique<WebServer>(port)) {
    server_->register_route("POST", "/api/chat", [this](const HttpRequest& req) { return handle_chat(req); });
    server_->register_route("POST", "/api/save", [this](const HttpRequest& req) { return handle_save(req); });
    server_->register_route("POST", "/api/load", [this](const HttpRequest& req) { return handle_load(req); });
    server_->register_route("GET", "/", [this](const HttpRequest& req) { return handle_ui(req); });
}

AGI_API::~AGI_API() { stop(); }
void AGI_API::start() { server_->start(); }
void AGI_API::stop() { server_->stop(); }

std::string AGI_API::json_escape(const std::string& str) {
    std::ostringstream oss;
    for (char c : str) {
        switch (c) {
            case '"': oss << "\\\""; break;
            case '\\': oss << "\\\\"; break;
            case '\n': oss << "\\n"; break;
            case '\r': oss << "\\r"; break;
            case '\t': oss << "\\t"; break;
            default: oss << c;
        }
    }
    return oss.str();
}

std::string AGI_API::sanitize_output(const std::string& raw) {
    std::string cleaned = raw;
    
    // Remove system markers
    size_t pos = 0;
    while ((pos = cleaned.find("[SYNAPTIC]:", pos)) != std::string::npos) {
        cleaned.erase(pos, 8);
    }
    while ((pos = cleaned.find("[SYNAPTIC]", pos)) != std::string::npos) {
        cleaned.erase(pos, 7);
    }
    
    // Remove sentiment markers
    const std::string markers[] = {"[positive]", "[negative]", "[neutral]"};
    for (const auto& marker : markers) {
        pos = 0;
        while ((pos = cleaned.find(marker, pos)) != std::string::npos) {
            cleaned.erase(pos, marker.length());
        }
    }
    
    // Trim whitespace
    cleaned.erase(0, cleaned.find_first_not_of(" \t\n\r"));
    cleaned.erase(cleaned.find_last_not_of(" \t\n\r") + 1);
    
    // Fix common grammar issues
    if (!cleaned.empty()) {
        // Capitalize first letter
        cleaned[0] = std::toupper(cleaned[0]);
        
        // Add period if missing
        char last = cleaned.back();
        if (last != '.' && last != '!' && last != '?') {
            cleaned += '.';
        }
        
        // Fix double spaces
        pos = 0;
        while ((pos = cleaned.find("  ", pos)) != std::string::npos) {
            cleaned.replace(pos, 2, " ");
        }
        
        // Fix space before punctuation
        pos = 0;
        while ((pos = cleaned.find(" .", pos)) != std::string::npos) {
            cleaned.erase(pos, 1);
        }
        pos = 0;
        while ((pos = cleaned.find(" ,", pos)) != std::string::npos) {
            cleaned.erase(pos, 1);
        }
        pos = 0;
        while ((pos = cleaned.find(" !", pos)) != std::string::npos) {
            cleaned.erase(pos, 1);
        }
        pos = 0;
        while ((pos = cleaned.find(" ?", pos)) != std::string::npos) {
            cleaned.erase(pos, 1);
        }
    }
    
    return cleaned;
}

HttpResponse AGI_API::handle_chat(const HttpRequest& req) {
    HttpResponse resp;
    resp.status_code = 200;
    
    std::string message;
    size_t msg_pos = req.body.find("\"message\":");
    if (msg_pos != std::string::npos) {
        size_t start = req.body.find('"', msg_pos + 10) + 1;
        // Walk forward respecting backslash escapes
        size_t end = start;
        while (end < req.body.size()) {
            if (req.body[end] == '\\') { end += 2; continue; }
            if (req.body[end] == '"')  { break; }
            ++end;
        }
        // Unescape the extracted substring
        std::string raw = req.body.substr(start, end - start);
        message.reserve(raw.size());
        for (size_t i = 0; i < raw.size(); ++i) {
            if (raw[i] == '\\' && i + 1 < raw.size()) {
                ++i;
                switch (raw[i]) {
                    case '"':  message += '"';  break;
                    case '\\': message += '\\'; break;
                    case 'n':  message += '\n'; break;
                    case 'r':  message += '\r'; break;
                    case 't':  message += '\t'; break;
                    default:   message += raw[i]; break;
                }
            } else {
                message += raw[i];
            }
        }
    }
    
    try {
        std::string raw_response = generateResponse(message);
        std::string sanitized = sanitize_output(raw_response);
        
        // Capture valence after response generation — reflects Synaptic's post-response emotional state
        double valence_snapshot = get_current_valence();

        std::ostringstream oss;
        oss << std::fixed << std::setprecision(4);
        oss << "{\"status\":\"ok\",\"response\":\"" << json_escape(sanitized)
            << "\",\"valence\":" << valence_snapshot << "}";
        resp.body = oss.str();
    } catch (const std::exception& e) {
        resp.body = "{\"status\":\"error\",\"message\":\"" + json_escape(e.what()) + "\"}";
        resp.status_code = 500;
    }
    return resp;
}

HttpResponse AGI_API::handle_save(const HttpRequest&) {
    HttpResponse resp;
    resp.status_code = 200;
    try {
        sv("state.dat");
        resp.body = "{\"status\":\"saved\"}";
    } catch (const std::exception& e) {
        resp.status_code = 500;
        resp.body = "{\"status\":\"error\",\"message\":\"" + json_escape(e.what()) + "\"}";
    }
    return resp;
}

HttpResponse AGI_API::handle_load(const HttpRequest&) {
    HttpResponse resp;
    resp.status_code = 200;
    try {
        ld("state.dat");
        resp.body = "{\"status\":\"loaded\"}";
    } catch (const std::exception& e) {
        resp.status_code = 500;
        resp.body = "{\"status\":\"error\",\"message\":\"" + json_escape(e.what()) + "\"}";
    }
    return resp;
}

HttpResponse AGI_API::handle_ui(const HttpRequest&) {
    HttpResponse resp;
    resp.status_code = 200;
    resp.headers["Content-Type"] = "text/html; charset=utf-8";
    resp.body = R"WTUI(<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Synaptic — WolfTech Innovations</title>
<style>
*{margin:0;padding:0;box-sizing:border-box}
html,body{width:100%;height:100%;overflow:hidden;background:#000}
canvas{display:block;position:fixed;inset:0}
#logo{
  position:fixed;
  top:28px;left:28px;
  width:64px;height:64px;
  z-index:10;
  opacity:0.92;
  mix-blend-mode:screen;
  transition:filter 0.4s ease;
  pointer-events:none;
}

#input-wrap{
  position:fixed;
  bottom:40px;
  left:50%;
  transform:translateX(-50%);
  z-index:10;
  display:flex;
  align-items:center;
  gap:0;
  width:min(520px,90vw);
  opacity:0;
  transition:opacity 0.6s;
}
#input-wrap.visible{opacity:1;}
#inp{
  flex:1;
  background:rgba(255,255,255,0.04);
  border:1px solid rgba(255,255,255,0.12);
  border-right:none;
  border-radius:4px 0 0 4px;
  color:#fff;
  font-size:15px;
  font-family:'Courier New',monospace;
  letter-spacing:0.04em;
  padding:13px 18px;
  outline:none;
  caret-color:rgba(255,255,255,0.7);
  transition:border-color 0.3s;
}
#inp::placeholder{color:rgba(255,255,255,0.2);}
#inp:focus{border-color:rgba(255,255,255,0.3);}
#send{
  background:rgba(255,255,255,0.07);
  border:1px solid rgba(255,255,255,0.12);
  border-radius:0 4px 4px 0;
  color:rgba(255,255,255,0.5);
  font-size:18px;
  padding:13px 18px;
  cursor:pointer;
  transition:all 0.2s;
  font-family:'Courier New',monospace;
}
#send:hover{background:rgba(255,255,255,0.13);color:#fff;}
#send:disabled{opacity:0.3;cursor:not-allowed;}
</style>
</head>
<body>
<canvas id="c"></canvas>
<img id="logo" src="data:image/png;base64," alt="WolfTech">
<div id="input-wrap">
  <input id="inp" type="text" placeholder="speak..." autocomplete="off" spellcheck="false">
  <button id="send">&#9656;</button>
</div>

<script>
// ── Canvas + 4-dot field ───────────────────────────────────────────────────
const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');
let W, H;

function resize(){
  W = canvas.width  = window.innerWidth;
  H = canvas.height = window.innerHeight;
  // Recompute dot base positions on resize
  for(const p of dots) p.rebase();
}
window.addEventListener('resize', resize);

// Valence state: -1 (negative) → 0 (neutral) → 1 (positive)
let valence = 0;         // target
let smoothValence = 0;   // smoothed
let waveAmplitude = 0;   // driven by audio playback
let wavePhase = 0;
let speaking = false;

// 4 dots arranged in a tight cluster at screen center
// Each has its own orbit phase so they move independently but cohesively
const DOT_CONFIGS = [
  { offsetX: -1, offsetY: -1, phase: 0           },
  { offsetX:  1, offsetY: -1, phase: Math.PI*0.5 },
  { offsetX:  1, offsetY:  1, phase: Math.PI      },
  { offsetX: -1, offsetY:  1, phase: Math.PI*1.5  },
];

class Dot {
  constructor(cfg, idx){
    this.cfg   = cfg;
    this.idx   = idx;
    this.phase = cfg.phase;
    this.waveFreq = 0.8 + idx * 0.35;
    this.rebase();
  }
  rebase(){
    // Base radius: ~4% of the smaller screen dimension — "medium" but scales
    this.baseR  = Math.min(W, H) * 0.042;
    // Spread: dots sit ~1.3 base-radii apart from center
    const spread = this.baseR * 1.35;
    this.bx = W/2 + this.cfg.offsetX * spread;
    this.by = H/2 + this.cfg.offsetY * spread;
  }
  update(t){
    smoothValence += (valence - smoothValence) * 0.025;

    // Wave orbit: each dot traces a small ellipse driven by amplitude
    const orbitR  = waveAmplitude * this.baseR * 1.8;
    const wx = orbitR * Math.sin(this.phase + t * this.waveFreq + wavePhase);
    const wy = orbitR * Math.cos(this.phase + t * this.waveFreq * 0.7 + wavePhase);

    // Valence vertical drift (subtle — keeps them near center)
    const vDrift = -smoothValence * this.baseR * 0.25;

    this.x = this.bx + wx;
    this.y = this.by + wy + vDrift;

    // Radius pulses with wave envelope
    this.r = this.baseR * (1 + waveAmplitude * 0.55 * Math.abs(Math.sin(this.phase + t * this.waveFreq)));

    // Color: negative → cool blue, positive → warm white, neutral → pure white
    const v = smoothValence;
    const rb = Math.round(255 * (v < 0 ? 1 + v * 0.45 : 1));
    const gb = Math.round(255 * (v < 0 ? 1 + v * 0.35 : 1));
    const alpha = 0.82 + waveAmplitude * 0.18;
    this.col = `rgba(${rb},${gb},255,${alpha})`;
  }
  draw(){
    // Soft glow — larger diffuse circle behind, sharp dot on top
    const glow = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, this.r * 2.8);
    glow.addColorStop(0,   this.col);
    glow.addColorStop(0.4, this.col.replace(/[\d.]+\)$/, '0.3)'));
    glow.addColorStop(1,   'rgba(0,0,0,0)');
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.r * 2.8, 0, Math.PI*2);
    ctx.fillStyle = glow;
    ctx.fill();

    // Solid core
    ctx.beginPath();
    ctx.arc(this.x, this.y, this.r, 0, Math.PI*2);
    ctx.fillStyle = this.col;
    ctx.fill();
  }
}

const dots = DOT_CONFIGS.map((cfg, i) => new Dot(cfg, i));
W = canvas.width  = window.innerWidth;
H = canvas.height = window.innerHeight;
for(const d of dots) d.rebase();

// ── Audio engine ──────────────────────────────────────────────────────────
let audioCtx = null;

function ensureAudio(){
  if(!audioCtx) audioCtx = new (window.AudioContext||window.webkitAudioContext)();
  if(audioCtx.state==='suspended') audioCtx.resume();
}

// Valence → melodic scale mapping
// Positive: major pentatonic (bright)
// Neutral:  natural minor (measured)
// Negative: phrygian-flavored (cold, tense)
function getScale(v){
  if(v > 0.25) return [261.63,293.66,329.63,392.00,440.00,523.25]; // C major penta
  if(v < -0.25) return [261.63,277.18,311.13,349.23,370.00,415.30]; // C phrygian
  return [261.63,293.66,311.13,349.23,392.00,440.00]; // C dorian (neutral)
}

function playTone(freq, duration, gainVal, delay=0, detune=0){
  ensureAudio();
  const g  = audioCtx.createGain();
  const osc= audioCtx.createOscillator();
  const flt= audioCtx.createBiquadFilter();

  // Waveform: positive=sine, neutral=triangle, negative=sawtooth
  osc.type = smoothValence > 0.25 ? 'sine' : smoothValence < -0.25 ? 'sawtooth' : 'triangle';
  osc.frequency.value = freq;
  osc.detune.value = detune;

  flt.type = 'lowpass';
  flt.frequency.value = 1800 + smoothValence * 1200;
  flt.Q.value = 0.8;

  osc.connect(flt);
  flt.connect(g);
  g.connect(audioCtx.destination);

  const now = audioCtx.currentTime + delay;
  g.gain.setValueAtTime(0, now);
  g.gain.linearRampToValueAtTime(gainVal, now + 0.05);
  g.gain.exponentialRampToValueAtTime(0.001, now + duration);

  osc.start(now);
  osc.stop(now + duration + 0.1);
}

function speakValence(text, detectedValence){
  valence = detectedValence;
  const scale = getScale(detectedValence);
  const words = text.trim().split(/\s+/).length;
  const noteCount = Math.min(Math.max(words, 4), 18);
  const baseDur = detectedValence > 0.25 ? 0.35 : detectedValence < -0.25 ? 0.55 : 0.45;
  const baseGain = 0.08 + Math.abs(detectedValence) * 0.06;

  speaking = true;
  let totalDuration = 0;

  for(let n = 0; n < noteCount; n++){
    const note = scale[Math.floor(Math.random()*scale.length)];
    // Occasionally jump an octave for expressiveness
    const oct = Math.random() < 0.15 ? 2 : Math.random() < 0.1 ? 0.5 : 1;
    const freq = note * oct;
    const dur = baseDur * (0.7 + Math.random()*0.8);
    const delay = n * (baseDur * 0.55 + Math.random()*0.15);
    const detune = (Math.random()-0.5)*18;
    const gain = baseGain * (0.6 + Math.random()*0.5);
    playTone(freq, dur, gain, delay, detune);
    totalDuration = delay + dur;
  }

  // Drive waveAmplitude over the duration
  const steps = 80;
  const stepTime = (totalDuration*1000)/steps;
  let step = 0;
  const amp = setInterval(()=>{
    const progress = step/steps;
    const envelope = Math.sin(progress*Math.PI); // bell curve
    waveAmplitude = envelope * (0.6 + Math.abs(detectedValence)*0.4);
    step++;
    if(step >= steps){
      clearInterval(amp);
      waveAmplitude = 0;
      speaking = false;
      valence = 0; // drift back to neutral over time
    }
  }, stepTime);


}

// ── Render loop ───────────────────────────────────────────────────────────
let t0 = performance.now();
function render(ts){
  requestAnimationFrame(render);
  const t = (ts - t0)*0.001;
  wavePhase += 0.012;

  ctx.fillStyle = 'rgba(0,0,0,0.18)';
  ctx.fillRect(0,0,W,H);

  for(const d of dots){ d.update(t); d.draw(); }
}
requestAnimationFrame(render);

// ── Chat logic ─────────────────────────────────────────────────────────────
const inp  = document.getElementById('inp');
const btn  = document.getElementById('send');
const wrap = document.getElementById('input-wrap');

setTimeout(()=>wrap.classList.add('visible'), 600);

let busy = false;
let lastValence = null;          // track previous valence to detect real change
const VALENCE_THRESHOLD = 0.08; // minimum delta to trigger audio/visual response

async function send(){
  if(busy) return;
  ensureAudio();
  const msg = inp.value.trim();
  if(!msg) return;
  inp.value = '';
  busy = true;
  btn.disabled = true;

  // Subtle think pulse — very low amplitude, not melodic
  const thinkInterval = setInterval(()=>{
    waveAmplitude = 0.04 + Math.random()*0.03;
  }, 150);

  try{
    const r = await fetch('/api/chat',{
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({message:msg})
    });
    const d = await r.json();
    clearInterval(thinkInterval);
    waveAmplitude = 0;

    if(d.status==='ok'){
      const v = typeof d.valence === 'number' ? d.valence : 0;
      const delta = lastValence === null ? Math.abs(v) : Math.abs(v - lastValence);

      // Only fire audio+visual response if valence actually shifted meaningfully
      if(delta >= VALENCE_THRESHOLD){
        speakValence(d.response, v);
        lastValence = v;
      } else {
        // Valence stable — tiny ripple only, no tone
        waveAmplitude = 0.12;
        setTimeout(()=>{ waveAmplitude = 0; }, 400);
      }
    } else {
      speakValence('error', -0.5);
    }
  } catch(e){
    clearInterval(thinkInterval);
    waveAmplitude = 0;
    speakValence('connection lost', -0.8);
  }

  busy = false;
  btn.disabled = false;
  inp.focus();
}

btn.addEventListener('click', send);
inp.addEventListener('keydown', e=>{
  if(e.key==='Enter'){ e.preventDefault(); send(); }
});
inp.focus();
</script>
</body>
</html>)WTUI";
    return resp;
}
